/// <summary>
/// QualitySpecificationGroup,25 Jan 2021 , Binay
/// </summary>
public void insert()
{

    ETG_ProductReceiptQualityGrp    eTG_ProductReceiptQualityGrp;
    ETG_VendPackingQualityGrp       eTG_VendPackingQualityGrp, vendPackingQualityGrpLoc;


    next insert();

    while select eTG_ProductReceiptQualityGrp 
        where eTG_ProductReceiptQualityGrp.InventTransId == this.InventTransId
    {
        eTG_VendPackingQualityGrp.GroupID         = eTG_ProductReceiptQualityGrp.GroupID;
        eTG_VendPackingQualityGrp.MaxRange        = eTG_ProductReceiptQualityGrp.MaxRange;
        eTG_VendPackingQualityGrp.MinRange        = eTG_ProductReceiptQualityGrp.MinRange;
        eTG_VendPackingQualityGrp.InventTransId   = this.InventTransId;
        eTG_VendPackingQualityGrp.SubGroupID      = eTG_ProductReceiptQualityGrp.SubGroupID;
        eTG_VendPackingQualityGrp.MeasurementType = eTG_ProductReceiptQualityGrp.MeasurementType;
        eTG_VendPackingQualityGrp.AdjustmentType  = eTG_ProductReceiptQualityGrp.AdjustmentType;
        eTG_VendPackingQualityGrp.Increment       = eTG_ProductReceiptQualityGrp.Increment;
        eTG_VendPackingQualityGrp.FixedValue      = eTG_ProductReceiptQualityGrp.FixedValue;
        eTG_VendPackingQualityGrp.ResultValue     = eTG_ProductReceiptQualityGrp.ResultValue;
        eTG_VendPackingQualityGrp.SubGroupDescription  = eTG_ProductReceiptQualityGrp.SubGroupDescription;
        eTG_VendPackingQualityGrp.VendPackingSlipTrans = this.VendPackingSlipJour; //QualitySpecificationGroup,25 Jan 2021 , Binay
        eTG_VendPackingQualityGrp.insert();
    }
 }

void  initFromVendPackingSlipJour(VendPackingSlipJour vendPackingSlipJour)
{
    next initFromVendPackingSlipJour(vendPackingSlipJour);

    this.BOLNo     = vendPackingSlipJour.BOLNo;
    this.BOLDate   = vendPackingSlipJour.BOLDate;
}
